  "SQUARE-SW": {
   "name": "SQUARE-SW",
   "file": "bad.zil",
   "line": 853,
   "endLine": 899,
   "desc": "Ostnitz Square, SW",
   "ldesc": "Here, at the southwest corner of Ostnitz Square, you can walk down either\nBesnap Street to the east and west, or Ostnitz Street to the north and\nsouth. In the Square, thousands of people have gathered for the\nfestivities which are to begin at noon.",
   "fdesc": "southwest corner of Ostnitz square",
   "loc": "ROOMS",
   "flags": [],
   "synonyms": [],
   "adjectives": [],
   "action": null,
   "descfcn": null,
   "contfcn": null,
   "globals": [],
   "pseudo": [],
   "otherProps": {
    "PATH": [
     "0"
    ],
    "PATH-TIME": [
     "0"
    ]
   },
   "exits": [
    {
     "to": "BLDG-2",
     "kind": "conditional",
     "condition": "FALSE-FLAG",
     "else": "\"You continue through the crowds as you head down Ostnitz Street, stopping\nfinally in front of a sidewalk cafe. Waiters here in traditional red robes\ncater to the mixed crowd of tourists and locals eager to watch the\nfestivities while sipping on a drink in the shade. Behind the cafe to\nthe west is the entrance to the building itself, which appears to be used as\noffice space. A pair of policemen guard the door - added security for the\noccasion.\"",
     "per": null,
     "message": null,
     "dir": "NORTH"
    },
    {
     "to": null,
     "kind": "blocked",
     "condition": null,
     "else": null,
     "per": null,
     "message": "You would be getting rather far from the action, and you've no time to\nspare getting sidetracked.",
     "dir": "SOUTH"
    },
    {
     "to": "BLDG-3",
     "kind": "conditional",
     "condition": "FALSE-FLAG",
     "else": "\"You continue along Besnap Street until you come to the front of a closed\nbookstore. The street continues east; the town square is just to the north.\"",
     "per": null,
     "message": null,
     "dir": "EAST"
    },
    {
     "to": "TOWN-SQUARE",
     "kind": "conditional",
     "condition": "FALSE-FLAG",
     "else": "\"You push your way through the crowd, reaching a spot near the middle of\nthe square where a graceful column stands, dedicated to the Litzenburgers\nwho died in the War of Independence which is celebrated here today.\nSurrounding the square on all sides are stately buildings dating from the 18th\ncentury, most of which now have storefronts on ground level.|\n|\nStretching from northeast through southeast, a series of barricades has been\nerected to separate the crowd from the dignitaries attending the ceremonies.\nHundreds of uniformed police guard the barricades, and scores of plainclothes\npolice are milling around nearby, heads cocked toward their earphones to\nenable them to hear over the ever louder crowd. The dais is raised about\nten feet, and the dignitaries are just starting to take their positions.\"",
     "per": null,
     "message": null,
     "dir": "NE"
    },
    {
     "to": "BLDG-8",
     "kind": "conditional",
     "condition": "FALSE-FLAG",
     "else": "\"You continue along Besnap Street until you come to the front of an\nantique shop. The sign outside says:|\n|\n   Riznik's Antiques|\n Rare Books and Curios|\n|\nThe gathering crowd which surrounds you continues its relentless push toward\nOstnitz Square to the east.\"",
     "per": null,
     "message": null,
     "dir": "WEST"
    }
   ],
   "contents": [],
   "source": "<ROOM SQUARE-SW\n      (LOC ROOMS)\n      (PATH 0)\n      (PATH-TIME 0)\n      (DESC \"Ostnitz Square, SW\")\n      (FDESC \"southwest corner of Ostnitz square\")\n      (LDESC\n\"Here, at the southwest corner of Ostnitz Square, you can walk down either\nBesnap Street to the east and west, or Ostnitz Street to the north and\nsouth. In the Square, thousands of people have gathered for the\nfestivities which are to begin at noon.\")\n      (NORTH TO BLDG-2 IF FALSE-FLAG ELSE\n\"You continue through the crowds as you head down Ostnitz Street, stopping\nfinally in front of a sidewalk cafe. Waiters here in traditional red robes\ncater to the mixed crowd of tourists and locals eager to watch the\nfestivities while sipping on a drink in the shade. Behind the cafe to\nthe west is the entrance to the building itself, which appears to be used as\noffice space. A pair of policemen guard the door - added security for the\noccasion.\")\n      (SOUTH SORRY\n\"You would be getting rather far from the action, and you've no time to\nspare getting sidetracked.\")\n      (EAST TO BLDG-3 IF FALSE-FLAG ELSE\n\"You continue along Besnap Street until you come to the front of a closed\nbookstore. The street continues east; the town square is just to the north.\")\n      (NE TO TOWN-SQUARE IF FALSE-FLAG ELSE\n\"You push your way through the crowd, reaching a spot near the middle of\nthe square where a graceful column stands, dedicated to the Litzenburgers\nwho died in the War of Independence which is celebrated here today.\nSurrounding the square on all sides are stately buildings dating from the 18th\ncentury, most of which now have storefronts on ground level.|\n|\nStretching from northeast through southeast, a series of barricades has been\nerected to separate the crowd from the dignitaries attending the ceremonies.\nHundreds of uniformed police guard the barricades, and scores of plainclothes\npolice are milling around nearby, heads cocked toward their earphones to\nenable them to hear over the ever louder crowd. The dais is raised about\nten feet, and the dignitaries are just starting to take their positions.\")\n      (WEST TO BLDG-8 IF FALSE-FLAG ELSE\n\"You continue along Besnap Street until you come to the front of an\nantique shop. The sign outside says:|\n|\n   Riznik's Antiques|\n Rare Books and Curios|\n|\nThe gathering crowd which surrounds you continues its relentless push toward\nOstnitz Square to the east.\")>",
   "referencedBy": []
  },
