   "exits": [
    {
     "to": "E3",
     "kind": "conditional",
     "condition": "HACK-FLAG",
     "else": "\"You stumble through a three-foot snowdrift, but get back on your\nfeet quickly and proceed through the forest.\"",
     "per": null,
     "message": null,
     "dir": "WEST"
    },
    {
     "to": null,
     "kind": "blocked",
     "condition": null,
     "else": null,
     "per": null,
     "message": "You'd be caught in a moment.",
     "dir": "EAST"
    },
    {
     "to": "G4",
     "kind": "conditional",
     "condition": "HACK-FLAG",
     "else": "\"You leave the forest, crossing a roadway, and come to the edge of a dank\narea at the edge of a swamp which continues to the south. Putrid sulphurous\nvapors fill your lungs as you step to the edge of the noisome waters.\"",
     "per": null,
     "message": null,
     "dir": "SE"
    },
    {
     "to": "E4",
     "kind": "conditional",
     "condition": "HACK-FLAG",
     "else": "\"You walk through the forest, breaking branches as you go, and\nfinally stop after walking about a hundred yards.\"",
     "per": null,
     "message": null,
     "dir": "SW"
    },
    {
     "to": "F4",
     "kind": "conditional",
     "condition": "HACK-FLAG",
     "else": "\"You emerge from the thick forest and come to a roadway running from\nnortheast to south.\"",
     "per": null,
     "message": null,
     "dir": "SOUTH"
    },
    {
     "to": null,
     "kind": "blocked",
     "condition": null,
     "else": null,
     "per": null,
     "message": "You scramble up a bit, but slide back down. It's just too steep.",
     "dir": "NORTH"
    },
    {
     "to": null,
     "kind": "blocked",
     "condition": null,
     "else": null,
     "per": null,
     "message": "You can't move any farther in that direction.",
     "dir": "NE"
    },
    {
     "to": "E2",
     "kind": "conditional",
     "condition": "HACK-FLAG",
     "else": "\"You continue through the forest, until you come to the edge of a wide\nclearing to the north - this is the border zone. From atop three guard\ntowers standing in a line from east to west, searchlights play across\nthe zone, brightly illuminating everything in their path. On either side\nof the towers are tall fences, running parallel to the border, making a\ndirect assault all but impossible.\"",
     "per": null,
     "message": null,
     "dir": "NW"
    }
   ],
   "contents": [],
   "source": "<ROOM F3\n      (EW 6)\n      (NS 3)\n      (LOC ROOMS)\n      (DESC \"Inside the Forest\")\n      (PATH 0)\n      (WEST TO E3 IF HACK-FLAG ELSE\n\"You stumble through a three-foot snowdrift, but get back on your\nfeet quickly and proceed through the forest.\")\n      (EAST SORRY\n\"You'd be caught in a moment.\")\n      (SE TO G4 IF HACK-FLAG ELSE\n\"You leave the forest, crossing a roadway, and come to the edge of a dank\narea at the edge of a swamp which continues to the south. Putrid sulphurous\nvapors fill your lungs as you step to the edge of the noisome waters.\")\n      (SW TO E4 IF HACK-FLAG ELSE\n\"You walk through the forest, breaking branches as you go, and\nfinally stop after walking about a hundred yards.\")\n      (SOUTH TO F4 IF HACK-FLAG ELSE\n\"You emerge from the thick forest and come to a roadway running from\nnortheast to south.\")\n      (NORTH SORRY\n\"You scramble up a bit, but slide back down. It's just too steep.\")\n      (NE SORRY\n\"You can't move any farther in that direction.\")\n      (NW TO E2 IF HACK-FLAG ELSE\n\"You continue through the forest, until you come to the edge of a wide\nclearing to the north - this is the border zone. From atop three guard\ntowers standing in a line from east to west, searchlights play across\nthe zone, brightly illuminating everything in their path. On either side\nof the towers are tall fences, running parallel to the border, making a\ndirect assault all but impossible.\")\n      (FLAGS FORESTBIT)\n      (ACTION FOREST-ROOM-F)>",
