  "RUN-WOOD-SEQUENCE": {
   "name": "RUN-WOOD-SEQUENCE",
   "file": "good.zil",
   "line": 1440,
   "endLine": 1461,
   "source": "<ROUTINE RUN-WOOD-SEQUENCE (\"AUX\" (L <LOC ,HUT-MAN>) NL)\n         <COND (<L? <SETG WOOD-COUNT <+ ,WOOD-COUNT 1>> 0>\n\t\t;\"Turned off by setting W-C to -10000\"\n\t\t<RTRUE>)\n\t       (<AND <EQUAL? ,WOOD-COUNT 1>\n\t\t     <NOT <IN? ,HUT-MAN ,HUT-LIVING>>>\n\t\t;\"Don't run this unless man is there\"\n\t\t<SETG WOOD-COUNT 0>)\n\t       (<EQUAL? .L <SET NL <GET ,WOOD-TBL ,WOOD-COUNT>>>\n\t\t;\"Stays in same place\"\n\t\t<RTRUE>)\n\t       (<0? .NL>\n\t\t<SETG WOOD-COUNT -10000>\n\t\t<RTRUE>)\n\t       (T\n\t\t<SETG HUT-MAN-FROM .L>\n\t\t<MOVE ,HUT-MAN .NL>\n\t\t<COND (<EQUAL? ,HERE .NL>\n\t\t       <CRLF>\n\t\t       <JIGS-UP ,HUT-MAN-HALT>)\n\t\t      (T\n\t\t       <APPLY <GETP .NL ,P?WOODFCN> .L>)>)>>"
  },
  "HUT-MUNGER": {
   "name": "HUT-MUNGER",
   "file": "good.zil",
   "line": 1470,
   "endLine": 1491,
   "source": "<ROUTINE HUT-MUNGER (\"AUX\" (RM <FIRST? ,ROOMS>) PRP PT DST)\n\t <REPEAT ()\n\t\t <COND (<ZERO? .RM> <RETURN>)>\n\t\t <SET PRP 0>\n\t\t <REPEAT ()\n\t\t\t <SET PRP <NEXTP .RM .PRP>>\n\t\t\t <COND (<ZERO? .PRP> <RETURN>)>\n\t\t\t <SET PT <GETPT .RM .PRP>>\n\t\t\t <COND (<EQUAL? <PTSIZE .PT> 5>\n\t\t\t\t<SET DST <GET .PT 0>>\n\t\t\t\t<COND (<OR <EQUAL? .DST\n\t\t\t\t\t\t   ,NORTH-HUT\n\t\t\t\t\t\t   ,SOUTH-HUT\n\t\t\t\t\t\t   ,OUTSIDE-HUT>\n\t\t\t\t\t   <EQUAL? .DST\n\t\t\t\t\t\t   ,BEHIND-HUT\n\t\t\t\t\t\t   ,D5>>\n\t\t\t\t       <PUT .PT\n\t\t\t\t\t    ,SEXITSTR\n\t\t\t\t\t    <GETP .DST\n\t\t\t\t\t\t  ,P?FIRE>>)>)>>\n\t\t <SET RM <NEXT? .RM>>>>"
  },
  "GLOBAL-SEARCHLIGHTS-F": {
   "name": "GLOBAL-SEARCHLIGHTS-F",
   "file": "good.zil",
   "line": 1500,
   "endLine": 1509,
   "source": "<ROUTINE GLOBAL-SEARCHLIGHTS-F ()\n\t <COND (<NOT <FSET? ,HERE ,GVIEWBIT>>\n\t\t<CANT-SEE ,SEARCHLIGHTS>)\n\t       (<VERB? EXAMINE>\n\t\t<TELL\n\"From this position, you can see the beam of the searchlights, but not the\nlights themselves. Your viewpoint also makes it impossible to correctly gauge\ntheir positions.\" CR>)\n\t       (T\n\t\t<TELL ,TOO-FAR CR>)>>"
  },
