  "BAD-YES-START": {
   "name": "BAD-YES-START",
   "kind": "global",
   "file": "bystander.zil",
   "line": 1647,
   "value": "\"You reply that indeed a wounded man did wander into the compartment,\napparently looking for someone. A moment later, he was gone. You are\nasked whether he gave you anything, a piece of paper perhaps, but you\nshake your head in the negative.\""
  },
