  "WARMTH-TBL": {
   "name": "WARMTH-TBL",
   "kind": "global",
   "file": "good.zil",
   "line": 417,
   "value": "<PTABLE \"You're shaking uncontrollably from the cold. It won't be long before you are competely incapacitated.\" \"You're shivering badly. If you don't find some warmth soon, it's hard to see how you can go on.\" \"Your teeth start to chatter from the cold; you are clearly slowing down, both physically and mentally.\" \"You've got quite a chill; you must move now to keep warm, but even this is not enough.\" \"In your confusion, you've all but forgotten how cold it is outside.\">"
  },
